exercises.tests:
const log = [];
const mw1 = (req, res, next) => { log.push('mw1'); req.x = 1; next(); };
const mw2 = (req, res, next) => { log.push('mw2'); req.x += 1; next(); };
const mwErr = (req, res, next) => { next('oops'); };

check('runs both middleware in order', () => {
  log.length = 0;
  const chain = compose(mw1, mw2);
  const req = {}, res = {};
  chain(req, res, (err) => { expect(err).toBe(undefined); });
  expect(log).toEqual(['mw1','mw2']);
  expect(req.x).toBe(2);
});

check('propagates error and stops chain', () => {
  log.length = 0;
  const chain = compose(mw1, mwErr, mw2);
  const req = {}, res = {};
  let caught;
  chain(req, res, (err) => { caught = err; });
  expect(caught).toBe('oops');
  expect(log).toEqual(['mw1']);
});

exercises.solution:
function compose(...fns) {
  return function(req, res, done) {
    let i = 0;
    function next(err) {
      if (err !== undefined || i >= fns.length) return done(err);
      const fn = fns[i++];
      try { fn(req, res, next); } catch(e) { done(e); }
    }
    next();
  };
}

