exercises.solution:
function httpStatus(operation, result) {
  if (result === 'notFound') return 404;
  if (result === 'unauthorized') return 401;
  if (result === 'forbidden') return 403;
  if (result === 'validationError') return 422;
  if (result === 'ok') {
    if (operation === 'create') return 201;
    return 200;
  }
  if (result === 'noContent') return 204;
  return 500;
}

