exercises.tests:
// fixed clock for deterministic tests
let t = 0;
const clock = () => t;

const consume = tokenBucket(10, 5, clock); // cap=10, 5 tokens/sec

check('starts full — can consume 10', () => {
  t = 0;
  expect(consume(10)).toBe(true);
});
check('bucket empty — consume fails', () => {
  expect(consume(1)).toBe(false);
});
check('after 1s, 5 tokens refilled', () => {
  t = 1000; // 1 second later
  expect(consume(5)).toBe(true);
});
check('cannot exceed capacity', () => {
  t = 10000; // 10s later — would add 50 tokens but cap is 10
  expect(consume(10)).toBe(true);
  expect(consume(1)).toBe(false);
});

exercises.solution:
function tokenBucket(capacity, refillPerSecond, now = () => Date.now()) {
  let tokens = capacity;
  let lastRefill = now();
  return function consume(n = 1) {
    const current = now();
    const elapsed = (current - lastRefill) / 1000;
    tokens = Math.min(capacity, tokens + elapsed * refillPerSecond);
    lastRefill = current;
    if (tokens >= n) {
      tokens -= n;
      return true;
    }
    return false;
  };
}

