exercises.tests:
const noSleep = () => Promise.resolve();
const noRand = () => 0.5;

check('succeeds on first try', async () => {
  let n = 0;
  const result = await retryWithBackoff(() => { n++; return Promise.resolve('ok'); }, 3, 10, noSleep, noRand);
  expect(result).toBe('ok');
  expect(n).toBe(1);
});

check('retries and succeeds on 3rd attempt', async () => {
  let n = 0;
  const fn = () => { n++; if (n < 3) return Promise.reject(new Error('fail')); return Promise.resolve('done'); };
  const result = await retryWithBackoff(fn, 3, 10, noSleep, noRand);
  expect(result).toBe('done');
  expect(n).toBe(3);
});

check('rejects after all attempts exhausted', async () => {
  let n = 0;
  const fn = () => { n++; return Promise.reject(new Error('always fails')); };
  let err;
  try { await retryWithBackoff(fn, 3, 10, noSleep, noRand); } catch(e) { err = e; }
  expect(err.message).toBe('always fails');
  expect(n).toBe(3);
});

exercises.solution:
async function retryWithBackoff(fn, maxAttempts, baseDelayMs, sleep = (ms) => new Promise(r => setTimeout(r, ms)), rand = Math.random) {
  let lastErr;
  for (let i = 0; i < maxAttempts; i++) {
    try {
      return await fn();
    } catch (e) {
      lastErr = e;
      if (i < maxAttempts - 1) {
        const delay = rand() * baseDelayMs * Math.pow(2, i);
        await sleep(delay);
      }
    }
  }
  throw lastErr;
}

