exercises.tests:
let fakeNow = 0;
const otp = createOtpStore(() => fakeNow);

check('generate returns 6-digit string', () => {
  fakeNow = 0;
  const code = otp.generate('555-1234');
  expect(typeof code).toBe('string');
  expect(code.length).toBe(6);
});

check('correct code → ok:true and invalidates', () => {
  fakeNow = 0;
  const code = otp.generate('555-0001');
  fakeNow = 1000;
  const r1 = otp.verify('555-0001', code);
  expect(r1.ok).toBe(true);
  // second use of same code should fail
  const r2 = otp.verify('555-0001', code);
  expect(r2.ok).toBe(false);
  expect(r2.reason).toBe('not_found');
});

check('wrong code → wrong_code', () => {
  fakeNow = 0;
  otp.generate('555-0002');
  fakeNow = 1000;
  const r = otp.verify('555-0002', '000000');
  expect(r.ok).toBe(false);
  expect(r.reason).toBe('wrong_code');
});

check('expired code → expired', () => {
  fakeNow = 0;
  const code = otp.generate('555-0003');
  fakeNow = 400000; // past 300s expiry
  const r = otp.verify('555-0003', code);
  expect(r.ok).toBe(false);
  expect(r.reason).toBe('expired');
});

check('max attempts → max_attempts', () => {
  fakeNow = 0;
  otp.generate('555-0004');
  fakeNow = 1000;
  for (let i = 0; i < 5; i++) otp.verify('555-0004', '000000');
  const r = otp.verify('555-0004', '000000');
  expect(r.ok).toBe(false);
  expect(r.reason).toBe('max_attempts');
});

exercises.solution:
function createOtpStore(now = () => Date.now()) {
  const store = {};

  function generate(phone) {
    const code = String(Math.floor(Math.random() * 1000000)).padStart(6, '0');
    store[phone] = { code, expiresAt: now() + 300000, attempts: 0 };
    return code;
  }

  function verify(phone, code) {
    const record = store[phone];
    if (!record) return { ok: false, reason: 'not_found' };
    if (now() > record.expiresAt) return { ok: false, reason: 'expired' };
    if (record.attempts >= 5) return { ok: false, reason: 'max_attempts' };
    if (record.code !== code) {
      record.attempts++;
      return { ok: false, reason: 'wrong_code' };
    }
    delete store[phone];
    return { ok: true };
  }

  return { generate, verify };
}

