exercises.solution:
function createRBAC(rolePermissions) {
  const map = { ...rolePermissions };
  return {
    can(roles, action) {
      const arr = Array.isArray(roles) ? roles : [roles];
      return arr.some(r => (map[r] || []).includes(action));
    },
    addRole(role, permissions) {
      map[role] = permissions;
    }
  };
}
